  private preferencesService: PreferencesService | null = null;
  private historyService: NotificationHistoryService | null = null;

parameters.new_string:
async send(payload: NotificationPayload): Promise<NotificationResult> {
  const queueKey = payload.recipient;
  const previousInQueue = this.sendQueues.get(queueKey) ?? Promise.resolve(undefined as unknown as NotificationResult);

  const resultPromise = previousInQueue
    .catch(() => {})
    .then(() => this.processSend(payload));

  this.sendQueues.set(queueKey, resultPromise);

  const result = await resultPromise;

  // Clean up queue entry if this was the last item
  if (this.sendQueues.get(queueKey) === resultPromise) {
    this.sendQueues.delete(queueKey);
  }

  return result;
}

private async processSend(payload: NotificationPayload): Promise<NotificationResult> {
  // Check user preferences if available — routes to channel-specific check
  if (this.preferencesService && payload.metadata?.['userId']) {
    const userId = payload.metadata['userId'] as string;
    if (!this.preferencesService.shouldSend(userId, payload.type, payload.channel)) {
      const result: NotificationResult = {
        success: true,
        notificationId: payload.id,
        channel: payload.channel,
        deliveredAt: new Date(),
      };
      this.logger.info(`Notification ${payload.id} skipped — user ${userId} opted out of ${payload.type} on ${payload.channel}`);
      if (this.historyService) {
        this.historyService.logSkipped(payload, `User ${userId} opted out of ${payload.type} on ${payload.channel}`);
      }
      return result;
    }
  }

  const adapter = this.adapters.get(payload.channel);

  if (!adapter) {
    const result: NotificationResult = {
      success: false,
      notificationId: payload.id,
      channel: payload.channel,
      error: `No adapter registered for channel: ${payload.channel}`,
      deliveredAt: new Date(),
    };
    const errorMsg = `No adapter registered for channel: ${payload.channel}`;
    this.records.push({ payload, result });
    if (this.historyService) {
      this.historyService.log(payload, result);
    }
    this.logger.warn(errorMsg);
    return result;
  }

  const result = await adapter.send(payload);
  this.records.push({ payload, result });
  if (this.historyService) {
    this.historyService.log(payload, result);
  }

  if (result.success) {
    this.logger.info(`Notification ${payload.id} sent via ${payload.channel} to ${payload.recipient}`);
  } else {
    this.logger.error(`Notification ${payload.id} failed via ${payload.channel}: ${result.error}`);
  }

  return result;
}

